import{_ as e,a as o}from"./chunks/common-save-actions.BbCaQ7WW.js";import{_ as i,c as a,o as s,ag as n}from"./chunks/framework.DD2hp6gW.js";const r="/assets/product-in-cart-selection.WSGkRFKh.png",c="/assets/product-in-cart-condition-empty.B-IlEZJZ.png",l="/assets/product-in-cart-trigger-product.T8itofNS.png",p="/assets/product-in-cart-discount-type-options.B_KFjhFD.png",u="/assets/product-in-cart-apply-on-options.DrHf8blb.png",d="/assets/product-in-cart-apply-on-specific.B0XVKqNm.png",g="/assets/product-in-cart-conditions-overview.CcC2Y27J.png",h="/assets/product-in-cart-sidebar-exclude-sale-item.D-He0EtH.png",m="/assets/product-in-cart-sidebar-usage-limit.BKSt8XYo.png",f="/assets/product-in-cart-sidebar-schedule-dates.BLV1wc94.png",y="/assets/product-in-cart-show-message.BnpH-ZAx.png",b="/assets/product-in-cart-message-format.CIxqvy0X.png",w=JSON.parse('{"title":"Campaign Type: Product In Cart","description":"","frontmatter":{},"headers":[],"relativePath":"campaigns/product-in-cart-discounts.md","filePath":"campaigns/product-in-cart-discounts.md","lastUpdated":1770144771000}'),_={name:"campaigns/product-in-cart-discounts.md"};function S(T,t,C,P,v,q){return s(),a("div",null,t[0]||(t[0]=[n('<h1 id="campaign-type-product-in-cart" tabindex="-1">Campaign Type: Product In Cart <a class="header-anchor" href="#campaign-type-product-in-cart" aria-label="Permalink to &quot;Campaign Type: Product In Cart&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Pro Feature</p><p>This is a <strong>CampaignBayPro</strong> feature. <a href="https://wpanchorbay.com/campaignbay" target="_blank" rel="noreferrer">Upgrade to Pro</a> to unlock Product In Cart discounts and other powerful features.</p></div><p>The <strong>Product In Cart</strong> campaign is a conditional discount type. It allows you to offer a discount on specific items (or the entire cart) <em>only if</em> a particular &quot;trigger product&quot; is present in the customer&#39;s cart.</p><p>This is ideal for membership-style perks or &quot;lock and key&quot; offers:</p><ul><li>&quot;Buy this <strong>Membership Card</strong> and get <strong>10% off everything</strong> else.&quot;</li><li>&quot;Add a <strong>Gift Box</strong> to your cart to get <strong>$5 off</strong> your jewelry purchase.&quot;</li></ul><h2 id="step-1-select-your-campaign-type" tabindex="-1">Step 1: Select Your Campaign Type <a class="header-anchor" href="#step-1-select-your-campaign-type" aria-label="Permalink to &quot;Step 1: Select Your Campaign Type&quot;">​</a></h2><p>To begin, navigate to <strong>CampaignBay → Add Campaign</strong>.</p><p><img src="'+r+'" alt="Select Campaign Type"></p><ul><li><strong>Select Discount Type:</strong> Choose <strong><code>Product In Cart</code></strong> from the list. This unlocks the conditional logic fields for trigger-based discounts.</li></ul><p><img src="'+e+'" alt="Campaign Title"></p><ul><li><strong>Campaign Title:</strong> Give your campaign a clear and descriptive name (e.g., &quot;VIP Membership Perk&quot;).</li></ul><p><img src="'+o+'" alt="Save Actions"></p><ul><li><strong>Select Status:</strong><ul><li><strong>Active:</strong> The campaign will be live immediately (or on its scheduled start time).</li><li><strong>Inactive:</strong> Save the campaign as a draft.</li></ul></li></ul><h2 id="step-2-define-the-conditions-discount" tabindex="-1">Step 2: Define the Conditions &amp; Discount <a class="header-anchor" href="#step-2-define-the-conditions-discount" aria-label="Permalink to &quot;Step 2: Define the Conditions &amp; Discount&quot;">​</a></h2><p>This campaign relies on a simple &quot;If This, Then That&quot; logic. You define which product triggers the discount and how that discount is applied.</p><p><img src="'+c+'" alt="Trigger and Discount Empty"></p><h3 id="_1-the-trigger-if-product" tabindex="-1">1. The Trigger (If product...) <a class="header-anchor" href="#_1-the-trigger-if-product" aria-label="Permalink to &quot;1. The Trigger (If product...)&quot;">​</a></h3><p>Select the <strong>trigger product</strong>. This is the item that must be in the customer&#39;s cart for the discount to activate.</p><p><img src="'+l+'" alt="Trigger Product"></p><ul><li><strong>Select a Product:</strong> Search for and select the item (e.g., &quot;VIP Membership&quot;).</li></ul><h3 id="_2-the-discount-apply" tabindex="-1">2. The Discount (Apply...) <a class="header-anchor" href="#_2-the-discount-apply" aria-label="Permalink to &quot;2. The Discount (Apply...)&quot;">​</a></h3><p>Enter the numeric <strong>value</strong> of the discount and choose the <strong>Discount Type</strong>:</p><p><img src="'+p+'" alt="Discount Type Options"></p><ul><li><strong>Percentage Discount (%):</strong> A percentage off the target items.</li><li><strong>Fixed Discount on Cart Total:</strong> A fixed amount off the total subtotal of the target items.</li><li><strong>Fixed Discount Per Item:</strong> A fixed amount off <strong>every</strong> individual target item in the cart.</li></ul><h3 id="_3-the-target-apply-discount-on" tabindex="-1">3. The Target (Apply discount on...) <a class="header-anchor" href="#_3-the-target-apply-discount-on" aria-label="Permalink to &quot;3. The Target (Apply discount on...)&quot;">​</a></h3><p>Choose which products are eligible for the discount once the trigger item is added:</p><p><img src="'+u+'" alt="Apply On Options"></p><ul><li><strong>Entire Store:</strong> Every other item in the cart gets the discount.</li><li><strong>Specific Products:</strong> Only specific items or categories you choose will be discounted.</li></ul><p><img src="'+d+'" alt="Specific Product Selection"></p><p>If you chose <strong>Specific Products</strong>, search for and select the eligible items in the secondary dropdown.</p><h2 id="step-3-set-conditions-optional" tabindex="-1">Step 3: Set Conditions (Optional) <a class="header-anchor" href="#step-3-set-conditions-optional" aria-label="Permalink to &quot;Step 3: Set Conditions (Optional)&quot;">​</a></h2><p>You can add specific rules to restrict who can use this discount.</p><p><img src="'+g+'" alt="Conditions Overview"></p><p><strong><a href="./../core-concepts/conditions.html">Read the Full Guide: How to Use Conditions →</a></strong></p><h2 id="step-4-set-other-configurations-optional" tabindex="-1">Step 4: Set Other Configurations (Optional) <a class="header-anchor" href="#step-4-set-other-configurations-optional" aria-label="Permalink to &quot;Step 4: Set Other Configurations (Optional)&quot;">​</a></h2><p>This section provides additional rules for your campaign.</p><p><img src="'+h+'" alt="Exclude Sale Item"></p><ul><li><strong>Exclude Sale Items:</strong> Check this box if you do not want this campaign&#39;s discount to apply to products that are already on sale in WooCommerce. This is useful for preventing &quot;double discounting.&quot;</li></ul><p><img src="'+m+'" alt="Enable Usage Limit"></p><ul><li><strong>Enable Usage Limit:</strong> Check this box to set a maximum number of times this campaign can be used across your entire store. Once the limit is reached, the campaign will automatically become inactive.</li></ul><h2 id="step-5-set-the-schedule-optional" tabindex="-1">Step 5: Set the Schedule (Optional) <a class="header-anchor" href="#step-5-set-the-schedule-optional" aria-label="Permalink to &quot;Step 5: Set the Schedule (Optional)&quot;">​</a></h2><p>You can optionally schedule your campaign to run during a specific time window. This section controls when your campaign will automatically start and end.</p><p><img src="'+f+'" alt="Enable Schedule"></p><ul><li><strong>Start Time / End Time:</strong> Use the date and time pickers to set the exact moment for the campaign to activate and expire.</li></ul><div class="tip custom-block"><p class="custom-block-title">Timezone Information</p><p>All dates and times are based on the timezone you have configured in your main WordPress settings under <strong>Settings → General → Timezone</strong>. The system automatically handles all UTC conversions for you.</p></div><div class="info custom-block"><p class="custom-block-title">Learn More About Automation</p><p>The status of your campaign is closely tied to the scheduling system, which uses WordPress Cron to automate activation and expiration.</p><p><strong><a href="./../core-concepts/scheduling-and-automation.html">Read the Full Guide: Scheduling &amp; Automation →</a></strong></p></div><h2 id="step-6-define-display-configurations" tabindex="-1">Step 6: Define Display Configurations <a class="header-anchor" href="#step-6-define-display-configurations" aria-label="Permalink to &quot;Step 6: Define Display Configurations&quot;">​</a></h2><p><img src="'+y+'" alt="Show Promo Message"></p><ul><li><strong>Show Product Page Message:</strong> Toggle this to enable or disable the custom message on the target product pages.</li></ul><p><img src="'+b+'" alt="Product Page Message"></p><ul><li><p><strong>Product Page Message Format:</strong> Customize the text using placeholders like <code>{campaign_title}</code> and <code>{discount_value}</code>.</p><ul><li><em>Example:</em> <code>{campaign_title} offer: Buy the VIP Pass and get {discount_value}% off this item!</code></li></ul></li><li><p><strong>Cart Page Discount Message Format:</strong> Enter a message to display on the cart page when the discount is applied.</p></li><li><p><strong>Cart Page Message Location:</strong> Choose where the cart message should appear.</p></li></ul><h2 id="step-7-save-the-campaign" tabindex="-1">Step 7: Save the Campaign <a class="header-anchor" href="#step-7-save-the-campaign" aria-label="Permalink to &quot;Step 7: Save the Campaign&quot;">​</a></h2><p>Once you have configured all the options, click the <strong>Save Campaign</strong> button. You will be redirected to the &quot;All Campaigns&quot; list.</p><p>You have now learned about all campaign types. It&#39;s time to explore the global settings that control your entire discount system.</p><ul><li><strong><a href="./../settings/">Configuring the Settings →</a></strong></li></ul>',55)]))}const I=i(_,[["render",S]]);export{w as __pageData,I as default};
